-- Helper: decode a base64url-encoded string
local function base64url_decode(input)
    local remainder = #input % 4
    if remainder > 0 then
        input = input .. string.rep("=", 4 - remainder)
    end
    input = input:gsub("-", "+"):gsub("_", "/")
    return ngx.decode_base64(input)
end

-- Helper: validate and decode a simple JWT-like token
-- Token format: base64url(header).base64url(payload).base64url(signature)
local function validate_token(token)
    if not token or token == "" then
        return nil, "missing token"
    end

    -- Split token into parts
    local parts = {}
    for part in string.gmatch(token, "[^%.]+") do
        table.insert(parts, part)
    end

    if #parts ~= 3 then
        return nil, "malformed token"
    end

    local header_b64 = parts[1]
    local payload_b64 = parts[2]
    local signature_b64 = parts[3]

    -- Verify signature using HMAC-SHA256
    local signing_input = header_b64 .. "." .. payload_b64
    local hmac = ngx.hmac_sha1(AUTH_SECRET, signing_input)
    local expected_signature = ngx.encode_base64(hmac):gsub("+", "-"):gsub("/", "_"):gsub("=", "")

    if signature_b64 ~= expected_signature then
        return nil, "invalid signature"
    end

    -- Decode payload
    local payload_json = base64url_decode(payload_b64)
    if not payload_json then
        return nil, "failed to decode payload"
    end

    local payload, err = cjson.decode(payload_json)
    if not payload then
        return nil, "failed to parse payload: " .. (err or "unknown error")
    end

    -- Check token expiration
    local now = ngx.time()
    if payload.exp and payload.exp < now then
        return nil, "token expired"
    end

    -- Check issued-at time (reject tokens from the future)
    if payload.iat and payload.iat > now + 60 then
        return nil, "token issued in the future"
    end

    return payload, nil
end

-- Helper: check if the current URI should skip permission checks
local function should_skip_permission_check(uri)
    for _, endpoint in ipairs(skip_endpoints) do
        if uri == endpoint or string.match(uri, "^" .. endpoint) then
            return true
        end
    end
    return false
end

-- Helper: check if a URI matches against allowed patterns for a role
local function check_role_permission(role, uri)
    local allowed_paths = role_permissions[role]
    if not allowed_paths then
        return false
    end

    for _, pattern in ipairs(allowed_paths) do
        -- Exact match
        if uri == pattern then
            return true
        end
        -- Pattern match (Lua patterns)
        if string.match(uri, "^" .. pattern) then
            return true
        end
    end

    return false
end

-- Helper: check if the URI is under /admin or /api paths
local function is_protected_path(uri)
    if string.match(uri, "^/admin") then
        return true, "admin"
    end
    if string.match(uri, "^/api") then
        return true, "api"
    end
    return false, nil
end

-- Main access control function
function _M.check_access()
    local uri = ngx.var.uri
    local request_method = ngx.var.request_method

    -- Log the incoming request
    ngx.log(ngx.INFO, "Access check for URI: ", uri, " Method: ", request_method)

    -- Step 1: Check if the endpoint should skip permission checks
    if should_skip_permission_check(uri) then
        ngx.log(ngx.INFO, "Skipping permission check for public endpoint: ", uri)
        return
    end

    -- Step 2: Check if this is a protected path (/admin or /api)
    local is_protected, path_type = is_protected_path(uri)

    if not is_protected then
        -- Not a protected path, allow access
        ngx.log(ngx.INFO, "URI is not a protected path, allowing access: ", uri)
        return
    end

    ngx.log(ngx.INFO, "Protected path detected (", path_type, "): ", uri)

    -- Step 3: Extract the authentication token
    local auth_header = ngx.var.http_authorization
    local token = nil

    if auth_header then
        -- Support "Bearer <token>" format
        token = string.match(auth_header, "^[Bb]earer%s+(.+)$")
        if not token then
            -- Try using the header value directly
            token = auth_header
        end
    end

    -- Also check for token in query parameter as fallback
    if not token then
        token = ngx.var.arg_token
    end

    -- Also check for token in cookie
    if not token then
        token = ngx.var.cookie_auth_token
    end

    if not token then
        ngx.log(ngx.WARN, "No authentication token found for protected path: ", uri)
        ngx.status = ngx.HTTP_UNAUTHORIZED
        ngx.header["Content-Type"] = "application/json"
        ngx.header["WWW-Authenticate"] = 'Bearer realm="protected"'
        ngx.say(cjson.encode({
            error = "unauthorized",
            message = "Authentication token is required"
        }))
        return ngx.exit(ngx.HTTP_UNAUTHORIZED)
    end

    -- Step 4: Validate the authentication token
    local payload, err = validate_token(token)
    if not payload then
        ngx.log(ngx.WARN, "Token validation failed: ", err, " for URI: ", uri)
        ngx.status = ngx.HTTP_UNAUTHORIZED
        ngx.header["Content-Type"] = "application/json"
        ngx.header["WWW-Authenticate"] = 'Bearer realm="protected", error="invalid_token"'
        ngx.say(cjson.encode({
            error = "unauthorized",
            message = "Invalid authentication token: " .. (err or "unknown error")
        }))
        return ngx.exit(ngx.HTTP_UNAUTHORIZED)
    end

    -- Step 5: Extract user information from the token payload
    local user_id = payload.sub or payload.user_id
    local user_role = payload.role or "viewer"
    local username = payload.username or "unknown"

    if not user_id then
        ngx.log(ngx.WARN, "Token payload missing user identifier for URI: ", uri)
        ngx.status = ngx.HTTP_UNAUTHORIZED
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode({
            error = "unauthorized",
            message = "Token payload is missing user identifier"
        }))
        return ngx.exit(ngx.HTTP_UNAUTHORIZED)
    end

    ngx.log(ngx.INFO, "Authenticated user: ", username, " (ID: ", user_id, ", Role: ", user_role, ")")

    -- Step 6: Check if the URI contains /admin and enforce admin-only access
    if string.match(uri, "/admin") then
        if not string.match(user_role, "^admin$") then
            ngx.log(ngx.WARN, "Non-admin user '", username, "' with role '", user_role,
                "' attempted to access admin path: ", uri)
            ngx.status = ngx.HTTP_FORBIDDEN
            ngx.header["Content-Type"] = "application/json"
            ngx.say(cjson.encode({
                error = "forbidden",
                message = "Admin access required for this endpoint"
            }))
            return ngx.exit(ngx.HTTP_FORBIDDEN)
        end
    end

    -- Step 7: Check role-based permissions for /api endpoints
    if string.match(uri, "/api") then
        local has_permission = check_role_permission(user_role, uri)
        if not has_permission then
            ngx.log(ngx.WARN, "User '", username, "' with role '", user_role,
                "' lacks permission for: ", uri)
            ngx.status = ngx.HTTP_FORBIDDEN
            ngx.header["Content-Type"] = "application/json"
            ngx.say(cjson.encode({
                error = "forbidden",
                message = "Insufficient permissions for this resource"
            }))
            return ngx.exit(ngx.HTTP_FORBIDDEN)
