    end

    local limit_dict = ngx.shared.rate_limit
    if not limit_dict then
        ngx.log(ngx.WARN, "Shared dict 'rate_limit' not configured, skipping rate limiting")
        return
    end

    local key = "rate:" .. user_id
    local count, err = limit_dict:incr(key, 1, 0, 60) -- 60 second window

    if not count then
        ngx.log(ngx.ERR, "Rate limit incr failed: ", err)
        return
    end

    local max_requests = 100 -- requests per minute

    ngx.header["X-RateLimit-Limit"] = max_requests
    ngx.header["X-RateLimit-Remaining"] = math.max(0, max_requests - count)

    if count > max_requests then
        ngx.log(ngx.WARN, "Rate limit exceeded for user: ", user_id)
        ngx.status = 429
        ngx.header["Content-Type"] = "application/json"
        ngx.header["Retry-After"] = "60"
        ngx.say(cjson.encode({
            error = "too_many_requests",
            message = "Rate limit exceeded. Please try again later."
        }))
        return ngx.exit(429)
    end
end

